import {
  Controller,
  Param,
  ParseUUIDPipe,
  Post,
  UseGuards,
} from '@nestjs/common';
import { ApiTags } from '@nestjs/swagger';
import type { QrTicketResponse } from '@smartcart/shared-types';
import {
  AuthenticatedUser,
  CurrentUser,
} from '../../../../common/decorators/current-user.decorator';
import { Roles } from '../../../../common/decorators/roles.decorator';
import { JwtAuthGuard } from '../../../../common/guards/jwt-auth.guard';
import { ResourceOwnershipGuard } from '../../../../common/guards/resource-ownership.guard';
import { RolesGuard } from '../../../../common/guards/roles.guard';
import { CheckoutService } from '../../application/services/checkout.service';

/**
 * QR generation endpoint (README §2.4 POST /sessions/:id/qr, §2.8 Workflow 4.5).
 * Finalizes the session and returns the signed, 10-minute checkout token.
 */
@ApiTags('sessions')
@Controller('sessions')
@UseGuards(JwtAuthGuard, RolesGuard)
@Roles('USER')
export class QrController {
  constructor(private readonly checkout: CheckoutService) {}

  @Post(':id/qr')
  @UseGuards(ResourceOwnershipGuard)
  generate(
    @CurrentUser() user: AuthenticatedUser,
    @Param('id', ParseUUIDPipe) id: string,
  ): Promise<QrTicketResponse> {
    return this.checkout.generateQr(id, user.sub);
  }
}
